/**
 * 计算数值的总和
 * 支持多种调用方式：
 * - sum(1, 2, 3) - 多个参数
 * - sum([1, 2, 3]) - 数组参数
 * - sum(1, 2, [3, 4], 5) - 混合参数
 * 
 * @param {...(number|number[])} args - 数字或数字数组
 * @returns {number} 所有数字的总和
 */
function sum(...args) {
  // 展平所有参数（处理数组嵌套）
  const flatten = (arr) => {
    return arr.reduce((acc, val) => {
      if (Array.isArray(val)) {
        return acc.concat(flatten(val));
      }
      return acc.concat(val);
    }, []);
  };

  const numbers = flatten(args);

  // 验证所有值都是数字
  for (const num of numbers) {
    if (typeof num !== 'number' || isNaN(num)) {
      throw new TypeError(`Invalid number: ${num}`);
    }
  }

  // 计算总和
  return numbers.reduce((total, num) => total + num, 0);
}

export default sum;

// 使用示例
if (import.meta.url === `file://${process.argv[1]}`) {
  console.log('=== Sum 函数测试 ===\n');

  // 测试 1: 多个参数
  console.log('测试 1 - 多个参数:');
  console.log(`sum(1, 2, 3, 4, 5) = ${sum(1, 2, 3, 4, 5)}`);

  // 测试 2: 数组参数
  console.log('\n测试 2 - 数组参数:');
  console.log(`sum([1, 2, 3, 4, 5]) = ${sum([1, 2, 3, 4, 5])}`);

  // 测试 3: 混合参数
  console.log('\n测试 3 - 混合参数:');
  console.log(`sum(1, 2, [3, 4], 5) = ${sum(1, 2, [3, 4], 5)}`);

  // 测试 4: 空参数
  console.log('\n测试 4 - 空参数:');
  console.log(`sum() = ${sum()}`);

  // 测试 5: 负数
  console.log('\n测试 5 - 负数:');
  console.log(`sum(-1, 2, -3, 4) = ${sum(-1, 2, -3, 4)}`);

  // 测试 6: 小数
  console.log('\n测试 6 - 小数:');
  console.log(`sum(0.1, 0.2, 0.3) = ${sum(0.1, 0.2, 0.3)}`);

  // 测试 7: 嵌套数组
  console.log('\n测试 7 - 嵌套数组:');
  console.log(`sum([1, [2, [3, [4, 5]]]]) = ${sum([1, [2, [3, [4, 5]]]])}`);
}

