/**
 * AI Coding Agent - 主循环
 *
 * 整体流程:
 *   while(true) {
 *     1. 等待用户输入 → 加入 messages
 *     2. 调 LLM（带 tools + messages 历史）→ 阻塞等待响应
 *     3. 遍历响应内容:
 *        - text → 显示给用户
 *        - tool_use → 执行工具 → 收集结果
 *     4. 如果有工具结果 → 加入 messages → 跳过用户输入 → 回到 2（工具循环）
 *        如果没有工具结果（end_turn）→ 回到 1（等用户）
 *   }
 *
 * 运行: npm start
 * 恢复会话: RESUME_FILE=logs/xxx-messages.json npm start
 */

import Anthropic from '@anthropic-ai/sdk';
import * as readline from 'readline';

import { API_KEY, BASE_URL, DEFAULT_MODEL, MAX_TOKENS, DEBUG, SYSTEM_PROMPT, RESUME_FILE } from './config.mjs';
import { toolSchemas, executeTool } from './tools.mjs';
import { status } from './display.mjs';
import { Logger, C } from './logger.mjs';
import { Messages } from './messages.mjs';

// Anthropic SDK 客户端，支持 baseURL 切换模型提供商
const client = new Anthropic({ apiKey: API_KEY, baseURL: BASE_URL });
const logger = new Logger(DEBUG);
const messages = new Messages();

async function main() {
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = (q) => new Promise(resolve => rl.question(q, resolve));

  const logFile = logger.init();
  messages.init(logFile);

  if (RESUME_FILE) {
    messages.load(RESUME_FILE);
  }

  logger.start({
    model: DEFAULT_MODEL,
    tools: toolSchemas.map(t => t.name),
    logFile,
    systemPrompt: SYSTEM_PROMPT,
    toolSchemas,
  });

  // stopReason 驱动循环行为:
  // - 'tool_use' → 跳过用户输入，直接再调 LLM（模型还在工作）
  // - 'max_tokens' → 输出被截断，继续调 LLM 接着输出
  // - 'end_turn' 或 null → 等待用户输入
  let stopReason = null;

  while (true) {
    // ── 步骤 1: 获取用户输入（工具循环中跳过）──────────────    
    if (stopReason !== 'tool_use' && stopReason !== 'max_tokens') {
      status('waiting');
      const input = await ask(`\x1b[32m你: \x1b[0m`);
      if (!input || input.trim() === 'exit') break;
      messages.push({ role: 'user', content: input });
    }

    if (stopReason === 'max_tokens') {
      logger.print(`${C.yellow}[续] 输出被截断，继续请求...${C.reset}`);
    }

    status('thinking');

    const requestParams = {
      model: DEFAULT_MODEL,
      max_tokens: MAX_TOKENS,
      system: SYSTEM_PROMPT,
      tools: toolSchemas,
      messages: messages.current,
    };

    logger.log('请求参数', {
      model: DEFAULT_MODEL,
      max_tokens: MAX_TOKENS,
      baseURL: BASE_URL || 'default',
      messages数量: messages.length,
    });

    let response;
    try {
      // ── 步骤 2: 调用 LLM ─────────────────────────────────
      // 每次都发送完整的 messages 历史 + 工具定义
      // 模型根据历史和工具描述，决定是回复文本还是调用工具
      response = await client.messages.create(requestParams);
    } catch (e) {
      status('error');
      logger.log('错误', e.message);
      stopReason = null;
      continue;
    }

    logger.log('响应内容', response);

    // 将 AI 响应加入历史（包含 text 和/或 tool_use blocks）
    messages.push({ role: 'assistant', content: response.content });
    stopReason = response.stop_reason;

    // ── 步骤 3: 处理响应内容 ──────────────────────────────
    const toolResults = [];

    for (const block of response.content) {
      if (block.type === 'text') {
        logger.print(`\n${C.cyan}Agent:${C.reset} ${block.text}\n`);

      } else if (block.type === 'tool_use') {
        status('calling');
        logger.log(`工具开始: ${block.name}`, block.input);

        const result = await executeTool(block.name, block.input);

        // 截断过长的工具结果，防止上下文窗口溢出
        const MAX = 8000;
        const truncated = result.length > MAX
          ? result.substring(0, MAX) + `\n... [截断，共 ${result.length} 字符]`
          : result;

        // 工具执行后记录
        logger.log(`工具完成: ${block.name}`, truncated);

        // tool_result 的 tool_use_id 必须匹配 tool_use 的 id（API 协议要求）
        toolResults.push({
          type: 'tool_result',
          tool_use_id: block.id,
          content: truncated,
        });
      }
    }

    // ── 步骤 4: 工具结果送回 → 决定下一轮行为 ──────────────
    if (toolResults.length > 0) {
      // 有工具结果 → 作为 user 消息送回（API 协议：tool_result 必须在 user 角色下）
      // stopReason 仍是 'tool_use'，下一轮会跳过用户输入，直接再调 LLM
      messages.push({ role: 'user', content: toolResults });
    } else if (stopReason === 'max_tokens') {
      // 截断时不等用户，继续调 LLM 接着输出
    } else {
      // 没有工具调用（end_turn）→ 任务完成，下一轮等待用户输入
      status('done');
    }
  }

  logger.print(`\n${C.dim}再见！${C.reset}\n`);
  rl.close();
}

main();

/**
 * Logger - 统一输出（终端 + 日志文件）
 *
 * 三个核心方法:
 *   print(text)        → 只输出到终端
 *   log(label, data)   → 终端（带颜色） + 日志文件
 *   start(...)         → 启动信息
 */

import { appendFileSync, mkdirSync } from 'fs';

const C = {
  reset:   '\x1b[0m',
  dim:     '\x1b[2m',
  bold:    '\x1b[1m',
  cyan:    '\x1b[36m',
  green:   '\x1b[32m',
  yellow:  '\x1b[33m',
  red:     '\x1b[31m',
  magenta: '\x1b[35m',
  blue:    '\x1b[34m',
};

const LABEL_COLORS = {
  '请求参数':   C.dim,
  '响应内容':   C.dim,
  '错误':       C.red,
};

function labelColor(label) {
  if (LABEL_COLORS[label]) return LABEL_COLORS[label];
  if (label.startsWith('工具开始')) return C.yellow;
  if (label.startsWith('工具完成')) return C.green;
  return C.dim;
}

export { C };

export class Logger {
  constructor(debug = false) {
    this.debug = debug;
    this.file = null;
  }

  init() {
    if (!this.debug) return null;
    mkdirSync('logs', { recursive: true });
    const now = new Date();
    const date = now.toISOString().split('T')[0];
    const time = now.toTimeString().split(' ')[0].replace(/:/g, '-');
    this.file = `logs/${date}_${time}.log`;
    this._write(`${'═'.repeat(50)}\n  Agent 启动 ${now.toLocaleString()}\n${'═'.repeat(50)}`);
    return this.file;
  }

  start({ model, tools, logFile, systemPrompt, toolSchemas }) {
    console.log(`\n${C.cyan}${C.bold}═══ AI Coding Agent ═══${C.reset}`);
    console.log(`${C.dim}模型: ${model}${C.reset}`);
    console.log(`${C.dim}工具: ${tools.join(', ')}${C.reset}`);
    if (logFile) console.log(`${C.dim}调试日志: ${logFile}${C.reset}`);
    console.log(`${C.dim}输入任务开始，exit 退出${C.reset}\n`);
    if (systemPrompt) this._section('System Prompt', systemPrompt);
    if (toolSchemas) this._section('可用工具', toolSchemas);
  }

  print(text) {
    console.log(text);
  }

  log(label, data) {
    const color = labelColor(label);
    if (data !== undefined) {
      const preview = typeof data === 'string' ? data : JSON.stringify(data);
      console.log(`${color}[${label}] ${preview.substring(0, 200)}${preview.length > 200 ? '...' : ''}${C.reset}`);
    } else {
      console.log(`${color}${label}${C.reset}`);
    }
    this._section(label, data);
  }

  _section(title, data) {
    if (data === undefined) return this._write(`\n────── ${title} ──────`);
    const content = typeof data === 'string' ? data : JSON.stringify(data, null, 2);
    this._write(`\n────── ${title} ──────\n${content}`);
  }

  _write(text) {
    if (!this.debug || !this.file) return;
    appendFileSync(this.file, `[${new Date().toLocaleString()}] ${text}\n`);
  }
}

/**
 * 工具定义与执行器
 *
 * 每个工具由两部分组成:
 *   1. schema — JSON Schema 描述（告诉 LLM 这个工具是什么、怎么调用）
 *   2. execute — 实际执行函数（接收 LLM 给的参数，返回字符串结果）
 */

import { readFile, writeFile, mkdir } from 'fs/promises';
import { execSync } from 'child_process';
import { dirname } from 'path';

// ─── 工具注册表 ──────────────────────────────────────────
// 所有工具在这里注册。LLM 只看到 schema，运行时根据 name 找到 execute 函数。
export const registry = {};

function define(name, description, properties, required, executeFn) {
  registry[name] = {
    schema: {
      name,
      description,
      input_schema: { type: 'object', properties, required }
    },
    execute: executeFn
  };
}

// ─── read_file ───────────────────────────────────────────
define(
  'read_file',
  '读取指定路径的文件内容。用于了解代码结构和内容。',
  { path: { type: 'string', description: '文件路径' } },
  ['path'],
  async ({ path }) => {
    try {
      return await readFile(path, 'utf-8');
    } catch (e) {
      return `错误: ${e.message}`;
    }
  }
);

// ─── write_file ──────────────────────────────────────────
define(
  'write_file',
  '将内容写入指定路径的文件。如果文件已存在则覆盖。自动创建父目录。',
  {
    path: { type: 'string', description: '文件路径' },
    content: { type: 'string', description: '要写入的完整文件内容' }
  },
  ['path', 'content'],
  async ({ path, content }) => {
    try {
      await mkdir(dirname(path), { recursive: true });
      await writeFile(path, content, 'utf-8');
      return `文件已写入: ${path} (${content.length} 字符)`;
    } catch (e) {
      return `写入失败: ${e.message}`;
    }
  }
);

// ─── execute_bash ────────────────────────────────────────
define(
  'execute_bash',
  '执行 bash 命令并返回输出。用于运行测试、安装依赖、git 操作、查看目录等。',
  { command: { type: 'string', description: '要执行的 bash 命令' } },
  ['command'],
  async ({ command }) => {
    try {
      const output = execSync(command, {
        encoding: 'utf-8',
        timeout: 30_000,
        maxBuffer: 1024 * 1024
      });
      return output || '(命令执行成功，无输出)';
    } catch (e) {
      return [
        `退出码: ${e.status ?? 'unknown'}`,
        e.stdout ? `stdout:\n${e.stdout}` : '',
        e.stderr ? `stderr:\n${e.stderr}` : ''
      ].filter(Boolean).join('\n');
    }
  }
);

// ─── 导出 ────────────────────────────────────────────────

/** 提供给 Anthropic API 的 tools 数组 */
export const toolSchemas = Object.values(registry).map(t => t.schema);

/** 根据工具名执行对应函数 */
export async function executeTool(name, input) {
  const tool = registry[name];
  if (!tool) return `未知工具: ${name}`;
  return tool.execute(input);
}

