{
  "name": "ink-ui-demo",
  "version": "1.0.0",
  "type": "module",
  "description": "Ink UI 示例 - 可集成到 agent-demo 项目",
  "scripts": {
    "demo": "node demo.mjs",
    "demo-simple": "node demo-simple.mjs",
    "demo-agent": "node demo-agent.mjs"
  },
  "dependencies": {
    "ink": "^4.4.1",
    "react": "^18.2.0"
  },
  "devDependencies": {
    "@types/react": "^18.2.0"
  }
}

/**
 * Status 组件 - 显示 Agent 状态
 * 
 * 对应原 display.mjs 的 status 函数
 */

import React from 'react';
import { Text, Box } from 'ink';

/**
 * 状态定义
 */
export const STATUS = {
  WAITING: 'waiting',
  THINKING: 'thinking',
  CALLING: 'calling',
  DONE: 'done',
  ERROR: 'error',
};

/**
 * 状态配置
 */
const STATUS_CONFIG = {
  [STATUS.WAITING]: {
    icon: '⏳',
    label: '等待输入',
    color: 'green',
  },
  [STATUS.THINKING]: {
    icon: '🧠',
    label: '思考中...',
    color: 'blue',
  },
  [STATUS.CALLING]: {
    icon: '⚡',
    label: '调用工具...',
    color: 'magenta',
  },
  [STATUS.DONE]: {
    icon: '✅',
    label: '完成',
    color: 'cyan',
  },
  [STATUS.ERROR]: {
    icon: '❌',
    label: '错误',
    color: 'red',
  },
};

/**
 * Status 组件
 * 
 * @param {object} props
 * @param {string} props.status - 状态值
 * @param {boolean} props.visible - 是否显示
 */
export default function Status({ status, visible = true }) {
  if (!visible || !status) return null;

  const config = STATUS_CONFIG[status] || { icon: '❓', label: status, color: 'white' };

  return (
    <Box>
      <Text color={config.color}>
        {config.icon} {config.label}
      </Text>
    </Box>
  );
}

/**
 * 导出状态常量，方便使用
 */
export { STATUS_CONFIG };

/**
 * Spinner 组件 - 动态加载动画
 * 
 * 用于思考中、工具调用等需要动画的场景
 */

import React, { useState, useEffect } from 'react';
import { Text } from 'ink';

/**
 * Spinner 动画帧
 */
const FRAMES = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];

/**
 * Spinner 组件
 * 
 * @param {object} props
 * @param {string} props.label - 标签文本
 * @param {string} props.color - 颜色
 * @param {boolean} props.visible - 是否显示
 */
export default function Spinner({ label = '加载中', color = 'cyan', visible = true }) {
  const [frame, setFrame] = useState(0);

  useEffect(() => {
    if (!visible) return;

    const timer = setInterval(() => {
      setFrame((prev) => (prev + 1) % FRAMES.length);
    }, 80);

    return () => clearInterval(timer);
  }, [visible]);

  if (!visible) return null;

  return (
    <Text color={color}>
      {FRAMES[frame]} {label}
    </Text>
  );
}

/**
 * Header 组件 - 显示 Agent 头部信息
 */

import React from 'react';
import { Text, Box } from 'ink';

/**
 * Header 组件
 * 
 * @param {object} props
 * @param {string} props.model - 模型名称
 * @param {string[]} props.tools - 工具列表
 * @param {string} props.logFile - 日志文件路径
 */
export default function Header({ model, tools = [], logFile }) {
  return (
    <Box flexDirection="column" marginBottom={1}>
      <Box>
        <Text bold color="cyan">
          ═══ AI Coding Agent ═══
        </Text>
      </Box>

      {model && (
        <Box>
          <Text dimColor>模型: </Text>
          <Text color="green">{model}</Text>
        </Box>
      )}

      {tools.length > 0 && (
        <Box>
          <Text dimColor>工具: </Text>
          <Text color="yellow">{tools.join(', ')}</Text>
        </Box>
      )}

      {logFile && (
        <Box>
          <Text dimColor>日志: </Text>
          <Text dimColor>{logFile}</Text>
        </Box>
      )}

      <Box marginTop={1}>
        <Text dimColor>输入任务开始，exit 退出</Text>
      </Box>
    </Box>
  );
}

/**
 * UserInput 组件 - 用户输入组件
 */

import React, { useState } from 'react';
import { Text, Box, useInput } from 'ink';

/**
 * UserInput 组件
 * 
 * @param {object} props
 * @param {function} props.onSubmit - 提交回调
 * @param {boolean} props.disabled - 是否禁用
 */
export default function UserInput({ onSubmit, disabled = false }) {
  const [input, setInput] = useState('');

  useInput((inputChar, key) => {
    if (disabled) return;

    if (key.return) {
      if (input.trim()) {
        onSubmit(input);
        setInput('');
      }
    } else if (key.backspace || key.delete) {
      setInput((prev) => prev.slice(0, -1));
    } else if (inputChar && !key.ctrl && !key.meta) {
      setInput((prev) => prev + inputChar);
    }
  });

  return (
    <Box>
      <Text bold color="green">
        你:{' '}
      </Text>
      <Text dimColor={disabled}>
        {input}
        {!disabled && <Text backgroundColor="green"> </Text>}
      </Text>
    </Box>
  );
}

/**
 * Message 组件 - 显示对话消息
 */

import React from 'react';
import { Text, Box } from 'ink';

/**
 * Message 组件
 * 
 * @param {object} props
 * @param {string} props.role - 角色 (user/assistant)
 * @param {string} props.content - 消息内容
 * @param {string} props.toolName - 工具名称（可选）
 */
export default function Message({ role, content, toolName }) {
  const isUser = role === 'user';
  const label = isUser ? '你' : 'Agent';
  const color = isUser ? 'green' : 'cyan';

  return (
    <Box flexDirection="column" marginBottom={1}>
      <Box>
        <Text bold color={color}>
          {label}:
        </Text>
        {toolName && (
          <Box marginLeft={1}>
            <Text dimColor>[调用 {toolName}]</Text>
          </Box>
        )}
      </Box>
      <Box marginLeft={2}>
        <Text>{content}</Text>
      </Box>
    </Box>
  );
}

/**
 * AgentUI - Agent 主界面组件
 * 
 * 集成所有子组件，提供完整的 Agent UI
 */

import React, { useState, useEffect } from 'react';
import { Box, Text, useApp, useInput } from 'ink';
import Header from './Header.mjs';
import Status, { STATUS } from './Status.mjs';
import Spinner from './Spinner.mjs';
import Message from './Message.mjs';

/**
 * AgentUI 组件
 * 
 * @param {object} props
 * @param {string} props.model - 模型名称
 * @param {string[]} props.tools - 工具列表
 * @param {string} props.logFile - 日志文件路径
 * @param {function} props.onUserInput - 用户输入回调
 * @param {string} props.status - 当前状态
 * @param {Array} props.messages - 消息历史
 */
export default function AgentUI({
  model,
  tools,
  logFile,
  onUserInput,
  status: currentStatus,
  messages = [],
}) {
  const [input, setInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const { exit } = useApp();

  // 监听用户输入
  useInput((inputChar, key) => {
    // 如果正在处理，禁用输入
    if (currentStatus === STATUS.THINKING || currentStatus === STATUS.CALLING) {
      return;
    }

    // 回车键 - 提交
    if (key.return) {
      if (input.trim().toLowerCase() === 'exit') {
        exit();
        return;
      }
      if (input.trim()) {
        onUserInput?.(input);
        setInput('');
      }
    }
    // 删除键
    else if (key.backspace || key.delete) {
      setInput((prev) => prev.slice(0, -1));
    }
    // 普通字符
    else if (inputChar && !key.ctrl && !key.meta) {
      setInput((prev) => prev + inputChar);
    }
  });

  // 渲染状态指示器
  const renderStatus = () => {
    if (currentStatus === STATUS.THINKING) {
      return <Spinner label="思考中..." color="blue" />;
    }
    if (currentStatus === STATUS.CALLING) {
      return <Spinner label="调用工具..." color="magenta" />;
    }
    return <Status status={currentStatus} />;
  };

  return (
    <Box flexDirection="column" padding={1}>
      {/* 头部信息 */}
      <Header model={model} tools={tools} logFile={logFile} />

      {/* 消息历史 */}
      <Box flexDirection="column" marginBottom={1}>
        {messages.map((msg, idx) => (
          <Message
            key={idx}
            role={msg.role}
            content={msg.content}
            toolName={msg.toolName}
          />
        ))}
      </Box>

      {/* 状态指示器 */}
      <Box marginBottom={1}>{renderStatus()}</Box>

      {/* 用户输入区 */}
      <Box>
        <Text bold color="green">
          你:{' '}
        </Text>
        <Text dimColor={currentStatus === STATUS.THINKING || currentStatus === STATUS.CALLING}>
          {input}
          {currentStatus !== STATUS.THINKING && currentStatus !== STATUS.CALLING && (
            <Text backgroundColor="green"> </Text>
          )}
        </Text>
      </Box>
    </Box>
  );
}

