/**
 * Agent 集成示例 - 展示如何在 agent-demo 项目中使用
 * 
 * 这个示例演示如何将 Ink UI 集成到现有的 agent.mjs
 */

import React, { useState, useEffect, useRef } from 'react';
import { render, Box, Text, useApp, useInput } from 'ink';
import Header from './components/Header.mjs';
import Status, { STATUS } from './components/Status.mjs';
import Spinner from './components/Spinner.mjs';
import Message from './components/Message.mjs';

/**
 * Agent 集成演示
 * 
 * 模拟 agent.mjs 的主循环，展示如何在 Ink 中实现相同功能
 */
const AgentDemo = () => {
  const { exit } = useApp();
  const [status, setStatus] = useState(STATUS.WAITING);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [currentText, setCurrentText] = useState('');

  // 模拟 AI 响应
  const simulateAIResponse = async (userInput) => {
    // 思考中
    setStatus(STATUS.THINKING);
    await sleep(1000);

    // 模拟流式输出
    const response = `收到你的输入: "${userInput}"\n\n我正在处理这个请求...\n完成了！`;
    let text = '';

    for (const char of response) {
      text += char;
      setCurrentText(text);
      await sleep(30);
    }

    // 添加到消息历史
    setMessages((prev) => [
      ...prev,
      { role: 'user', content: userInput },
      { role: 'assistant', content: response },
    ]);
    setCurrentText('');

    // 完成
    setStatus(STATUS.DONE);
    await sleep(500);
    setStatus(STATUS.WAITING);
  };

  // 监听用户输入
  useInput((inputChar, key) => {
    // 禁用处理中的输入
    if (status === STATUS.THINKING || status === STATUS.CALLING) {
      return;
    }

    if (key.return) {
      const trimmed = input.trim();
      if (trimmed.toLowerCase() === 'exit') {
        exit();
        return;
      }
      if (trimmed) {
        simulateAIResponse(trimmed);
        setInput('');
      }
    } else if (key.backspace || key.delete) {
      setInput((prev) => prev.slice(0, -1));
    } else if (inputChar && !key.ctrl && !key.meta) {
      setInput((prev) => prev + inputChar);
    }
  });

  // 渲染状态指示器
  const renderStatus = () => {
    if (status === STATUS.THINKING) {
      return <Spinner label="思考中..." color="blue" />;
    }
    if (status === STATUS.CALLING) {
      return <Spinner label="调用工具..." color="magenta" />;
    }
    return <Status status={status} />;
  };

  const isProcessing = status === STATUS.THINKING || status === STATUS.CALLING;

  return (
    <Box flexDirection="column" padding={1}>
      {/* 头部 */}
      <Header
        model="claude-3-sonnet"
        tools={['read_file', 'write_file', 'execute_bash']}
        logFile="logs/agent.log"
      />

      {/* 消息历史 */}
      {messages.length > 0 && (
        <Box flexDirection="column" marginBottom={1}>
          {messages.map((msg, idx) => (
            <Message key={idx} role={msg.role} content={msg.content} />
          ))}
        </Box>
      )}

      {/* 当前正在输出的文本 */}
      {currentText && (
        <Box marginBottom={1}>
          <Text bold color="cyan">
            Agent:{' '}
          </Text>
          <Text>{currentText}</Text>
        </Box>
      )}

      {/* 状态指示器 */}
      <Box marginBottom={1}>{renderStatus()}</Box>

      {/* 用户输入区 */}
      <Box>
        <Text bold color="green">
          你:{' '}
        </Text>
        <Text dimColor={isProcessing}>
          {input}
          {!isProcessing && <Text backgroundColor="green"> </Text>}
        </Text>
      </Box>

      {/* 提示信息 */}
