import React from 'react';
import { Text, Box } from 'ink';

/**
 * 状态定义
 */
export const STATUS = {
  WAITING: 'waiting',
  THINKING: 'thinking',
  CALLING: 'calling',
  DONE: 'done',
  ERROR: 'error',
};

/**
 * 状态配置
 */
export const STATUS_CONFIG = {
  [STATUS.WAITING]: {
    icon: '⏳',
    label: '等待输入',
    color: 'green',
  },
  [STATUS.THINKING]: {
    icon: '🧠',
    label: '思考中...',
    color: 'blue',
  },
  [STATUS.CALLING]: {
    icon: '⚡',
    label: '调用工具...',
    color: 'magenta',
  },
  [STATUS.DONE]: {
    icon: '✅',
    label: '完成',
    color: 'cyan',
  },
  [STATUS.ERROR]: {
    icon: '❌',
    label: '错误',
    color: 'red',
  },
};

/**
 * Status 组件
 * 
 * @param {object} props
 * @param {string} props.status - 状态值
 * @param {boolean} props.visible - 是否显示
 */
export default function Status({ status, visible = true }) {
  if (!visible || !status) return null;

  const config = STATUS_CONFIG[status] || { icon: '❓', label: status, color: 'white' };

  return React.createElement(
    Box,
    null,
    React.createElement(
      Text,
      { color: config.color },
      `${config.icon} ${config.label}`
    )
  );
}

/**
 * Spinner 组件 - 动态加载动画
 * 
 * 用于思考中、工具调用等需要动画的场景
 */

import React, { useState, useEffect } from 'react';
import { Text } from 'ink';

/**
 * Spinner 动画帧
 */
const FRAMES = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];

/**
 * Spinner 组件
 * 
 * @param {object} props
 * @param {string} props.label - 标签文本
 * @param {string} props.color - 颜色
 * @param {boolean} props.visible - 是否显示
 */
export default function Spinner({ label = '加载中', color = 'cyan', visible = true }) {
  const [frame, setFrame] = useState(0);

  useEffect(() => {
    if (!visible) return;

    const timer = setInterval(() => {
      setFrame((prev) => (prev + 1) % FRAMES.length);
    }, 80);

    return () => clearInterval(timer);
  }, [visible]);

  if (!visible) return null;

  return React.createElement(
    Text,
    { color },
    `${FRAMES[frame]} ${label}`
  );
}

