 * 
 * 这个示例演示如何将 Ink UI 集成到现有的 agent.mjs
 * 
 * 运行方式：
 * cd examples/ink-ui
 * node integration-example.mjs
 */

import Anthropic from '@anthropic-ai/sdk';
import { status, createAgentUI } from './ink-display.mjs';
import { API_KEY, BASE_URL, DEFAULT_MODEL, MAX_TOKENS, SYSTEM_PROMPT } from '../../src/config.mjs';
import { toolSchemas, executeTool } from '../../src/tools.mjs';

// 使用 createAgentUI 创建 UI 控制器（可选）
const ui = createAgentUI({
  model: DEFAULT_MODEL,
  tools: toolSchemas.map(t => t.name),
  logFile: 'logs/integration-demo.log',
});

// 使用 Anthropic SDK
const client = new Anthropic({ apiKey: API_KEY, baseURL: BASE_URL });

// 简单的 messages 管理
const messages = [];

/**
 * 主循环示例
 */
async function main() {
  console.log('\n═══ Agent 集成示例 ═══\n');
  console.log('展示如何在 agent-demo 中使用 Ink UI\n');

  // 使用 status 函数（与原 display.mjs 完全一致）
  status('waiting');

  // 模拟一个简单的对话
  const userMessage = '你好，请介绍一下你自己';

  console.log(`\n用户: ${userMessage}\n`);
  messages.push({ role: 'user', content: userMessage });

  // 思考中
  status('thinking');

  try {
    // 调用 API
    const response = await client.messages.create({
      model: DEFAULT_MODEL,
      max_tokens: MAX_TOKENS,
      system: SYSTEM_PROMPT,
      tools: toolSchemas,
      messages: messages,
    });

    // 完成
    status('done');

    // 显示响应
    console.log('\nAgent 响应:');
    for (const block of response.content) {
      if (block.type === 'text') {
        console.log(block.text);
      } else if (block.type === 'tool_use') {
        status('calling');
        console.log(`\n[调用工具: ${block.name}]`);

        const result = await executeTool(block.name, block.input);
        console.log(`结果: ${result.substring(0, 100)}...`);

        status('done');
      }
    }

    console.log('\n✅ 示例完成！');
    console.log('\n💡 提示:');
    console.log('  - status() 函数与原 display.mjs 完全兼容');
    console.log('  - 可以直接替换 src/display.mjs 中的 status 函数');
    console.log('  - createAgentUI() 提供了更高级的 UI 控制');

  } catch (error) {
    status('error');
    console.error('\n错误:', error.message);
  }
}

main();

