/**
 * Ink UI 适配器 - 用于替换 display.mjs
 * 
 * 这个文件提供了与 display.mjs 相同的接口，但使用 Ink 实现
 * 可以直接替换使用，无需修改 agent.mjs
 */

import React from 'react';
import { render, Box, Text } from 'ink';
import Status, { STATUS, STATUS_CONFIG } from './components/Status.mjs';

// 导出颜色常量（与原 display.mjs 保持一致）
export const C = {
  reset: '\x1b[0m',
  dim: '\x1b[2m',
  cyan: '\x1b[36m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
};

// 状态映射（与原 display.mjs 保持一致）
const STATUS_MAP = {
  waiting: STATUS.WAITING,
  thinking: STATUS.THINKING,
  calling: STATUS.CALLING,
  done: STATUS.DONE,
  error: STATUS.ERROR,
};

// 全局状态
let currentApp = null;

/**
 * 状态显示函数 - 与原 display.mjs 的 status 函数接口一致
 * 
 * @param {string} state - 状态名称 (waiting, thinking, calling, done, error)
 */
export function status(state) {
  const mappedStatus = STATUS_MAP[state];

  if (!mappedStatus) {
    // 如果状态不存在，使用原 ANSI 方式
    const labels = {
      waiting: `${C.green}⏳ 等待输入${C.reset}`,
      thinking: `${C.blue}🧠 思考中...${C.reset}`,
      calling: `${C.magenta}⚡ 调用工具...${C.reset}`,
      done: `${C.cyan}✅ 完成${C.reset}`,
      error: `${C.yellow}❌ 错误${C.reset}`,
    };
    process.stdout.write(`\r${labels[state] || state}  \r`);
    return;
  }

  // 使用 Ink 渲染状态
  const config = STATUS_CONFIG[mappedStatus];

  // 清除当前行并渲染新状态
  process.stdout.write('\r\x1b[K'); // 清除整行
  process.stdout.write(`${config.icon} ${config.label}`);
}

/**
 * 创建持续的 Ink UI（可选方案）
 * 
 * 如果你想要一个持续运行的 UI（而不是每次都重新渲染），
 * 可以使用这个函数创建一个持久的 UI 实例
 * 
 * @param {object} options - 配置选项
 * @returns {object} UI 控制器
 */
export function createAgentUI(options = {}) {
  const { model, tools, logFile } = options;

  let currentStatus = STATUS.WAITING;
  let messages = [];

  // 返回控制器
  return {
    /**
     * 设置状态
     */
    setStatus(newStatus) {
      currentStatus = STATUS_MAP[newStatus] || newStatus;
    },

    /**
     * 添加消息
     */
    addMessage(role, content, toolName) {
      messages.push({ role, content, toolName });
    },

    /**
     * 获取当前状态
     */
    getStatus() {
      return currentStatus;
    },

    /**
     * 获取消息历史
     */
    getMessages() {
      return messages;
    },

    /**
     * 清空消息
     */
    clearMessages() {
      messages = [];
    },
  };
}

/**
 * 导出组件（供高级用户使用）
 */
export { Status, STATUS, STATUS_CONFIG };

/**
 * Status 组件 - 显示 Agent 状态
 * 
 * 对应原 display.mjs 的 status 函数
 */

import React from 'react';
import { Text, Box } from 'ink';

/**
 * 状态定义
 */
export const STATUS = {
  WAITING: 'waiting',
  THINKING: 'thinking',
  CALLING: 'calling',
  DONE: 'done',
  ERROR: 'error',
};

/**
 * 状态配置
 */
export const STATUS_CONFIG = {
  [STATUS.WAITING]: {
    icon: '⏳',
    label: '等待输入',
    color: 'green',
  },
  [STATUS.THINKING]: {
    icon: '🧠',
    label: '思考中...',
    color: 'blue',
  },
  [STATUS.CALLING]: {
    icon: '⚡',
    label: '调用工具...',
    color: 'magenta',
  },
  [STATUS.DONE]: {
    icon: '✅',
    label: '完成',
    color: 'cyan',
  },
  [STATUS.ERROR]: {
    icon: '❌',
    label: '错误',
    color: 'red',
  },
};

/**
 * Status 组件
 * 
 * @param {object} props
 * @param {string} props.status - 状态值
 * @param {boolean} props.visible - 是否显示
 */
export default function Status({ status, visible = true }) {
  if (!visible || !status) return null;

  const config = STATUS_CONFIG[status] || { icon: '❓', label: status, color: 'white' };

  return React.createElement(
    Box,
    null,
    React.createElement(
      Text,
      { color: config.color },
      `${config.icon} ${config.label}`
    )
  );
}

/**
 * AgentUI - Agent 主界面组件
 * 
 * 集成所有子组件，提供完整的 Agent UI
 */

import React, { useState } from 'react';
import { Box, Text, useApp, useInput } from 'ink';
import Header from './Status.mjs';
import Status, { STATUS } from './Status.mjs';
import Spinner from './Spinner.mjs';
import Message from './Message.mjs';

/**
 * AgentUI 组件
 * 
 * @param {object} props
 * @param {string} props.model - 模型名称
 * @param {string[]} props.tools - 工具列表
 * @param {string} props.logFile - 日志文件路径
 * @param {function} props.onUserInput - 用户输入回调
 * @param {string} props.status - 当前状态
 * @param {Array} props.messages - 消息历史
 */
export default function AgentUI({
  model,
  tools,
  logFile,
  onUserInput,
  status: currentStatus,
  messages = [],
}) {
  const [input, setInput] = useState('');
  const { exit } = useApp();

  // 监听用户输入
  useInput((inputChar, key) => {
    // 如果正在处理，禁用输入
    if (currentStatus === STATUS.THINKING || currentStatus === STATUS.CALLING) {
      return;
    }

    // 回车键 - 提交
    if (key.return) {
      if (input.trim().toLowerCase() === 'exit') {
        exit();
        return;
      }
      if (input.trim()) {
        onUserInput?.(input);
        setInput('');
      }
    }
    // 删除键
    else if (key.backspace || key.delete) {
      setInput((prev) => prev.slice(0, -1));
    }
    // 普通字符
    else if (inputChar && !key.ctrl && !key.meta) {
      setInput((prev) => prev + inputChar);
    }
  });

  // 渲染状态指示器
  const renderStatus = () => {
    if (currentStatus === STATUS.THINKING) {
      return React.createElement(Spinner, { label: '思考中...', color: 'blue' });
    }
    if (currentStatus === STATUS.CALLING) {
      return React.createElement(Spinner, { label: '调用工具...', color: 'magenta' });
    }
    return React.createElement(Status, { status: currentStatus });
  };

  // 消息列表
  const messageElements = messages.map((msg, idx) =>
    React.createElement(Message, {
      key: idx,
      role: msg.role,
      content: msg.content,
      toolName: msg.toolName,
    })
  );

  // 输入框
  const isProcessing = currentStatus === STATUS.THINKING || currentStatus === STATUS.CALLING;
  const inputChildren = [
    React.createElement(Text, { bold: true, color: 'green', key: 'label' }, '你: '),
    React.createElement(Text, { dimColor: isProcessing, key: 'input' }, input),
  ];

  if (!isProcessing) {
    inputChildren.push(
      React.createElement(Text, { backgroundColor: 'green', key: 'cursor' }, ' ')
    );
  }

  // 主容器
  return React.createElement(
    Box,
    { flexDirection: 'column', padding: 1 },
    [
      // 头部信息
      React.createElement(Header, {
        key: 'header',
        model,
        tools,
        logFile,
      }),
      // 消息历史
      messageElements.length > 0 &&
        React.createElement(
          Box,
          { key: 'messages', flexDirection: 'column', marginBottom: 1 },
          messageElements
        ),
      // 状态指示器
      React.createElement(Box, { key: 'status', marginBottom: 1 }, renderStatus()),
      // 用户输入区
      React.createElement(Box, { key: 'input' }, inputChildren),
    ].filter(Boolean)
  );
}

{
  "name": "ink-ui-demo",
  "version": "1.0.0",
  "type": "module",
  "description": "Ink UI 示例 - 可集成到 agent-demo 项目",
  "scripts": {
    "demo": "node demo.mjs",
    "demo-simple": "node demo-simple.mjs",
    "demo-agent": "node demo-agent.mjs"
  },
  "dependencies": {
    "ink": "^4.4.1",
    "react": "^18.2.0"
  },
  "devDependencies": {
    "@types/react": "^18.2.0"
  }
}

