#!/usr/bin/env node

/**
 * 快速开始脚本 - 演示 Ink UI 的所有功能
 */

import { status, C, createAgentUI } from './ink-display.mjs';

console.log(`
${C.cyan}══════════════════════════════════════${C.reset}
${C.cyan}  Ink UI 快速演示${C.reset}
${C.cyan}══════════════════════════════════════${C.reset}
`);

// 1. 演示 status 函数
console.log(`${C.bold}1. status() 函数演示${C.reset}`);
console.log('   这个函数可以直接替换 display.mjs 中的 status\n');

const states = ['waiting', 'thinking', 'calling', 'done', 'error'];
for (const state of states) {
  process.stdout.write('   ');
  status(state);
  console.log();
}

await sleep(500);

// 2. 演示 createAgentUI
console.log(`\n${C.bold}2. createAgentUI() 演示${C.reset}`);
console.log('   提供更强大的 UI 控制能力\n');

const ui = createAgentUI({
  model: 'claude-3-sonnet',
  tools: ['read_file', 'write_file', 'execute_bash'],
  logFile: 'logs/demo.log'
});

console.log(`   ✓ UI 控制器创建成功`);
console.log(`   ✓ 可用方法: ${Object.keys(ui).join(', ')}`);

ui.setStatus('thinking');
console.log(`   ✓ 设置状态: ${ui.getStatus()}`);

ui.addMessage('user', '你好');
ui.addMessage('assistant', '你好！有什么可以帮助你的吗？');
console.log(`   ✓ 添加消息: ${ui.getMessages().length} 条`);

await sleep(500);

// 3. 演示颜色常量
console.log(`\n${C.bold}3. 颜色常量 C${C.reset}`);
console.log('   与原 display.mjs 完全一致\n');

console.log(`   ${C.green}✓ 绿色${C.reset} - waiting`);
console.log(`   ${C.blue}✓ 蓝色${C.reset} - thinking`);
console.log(`   ${C.magenta}✓ 品红${C.reset} - calling`);
console.log(`   ${C.cyan}✓ 青色${C.reset} - done`);
console.log(`   ${C.yellow}✓ 黄色${C.reset} - error`);

await sleep(500);

// 4. 集成指南
